registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLength: 48,
    lastX: g.px,
    lastY: g.py
  };

  var trail = g._trail;
  var ctx = g.ctx;
  var dx = g.px - trail.lastX;
  var dy = g.py - trail.lastY;
  var moved = dx * dx + dy * dy > 0.1;

  if (moved) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLength) {
      trail.points.shift();
    }
    trail.lastX = g.px;
    trail.lastY = g.py;
  }

  var len = trail.points.length;
  if (len < 2) return;

  for (var i = 1; i < len; i++) {
    var p = trail.points[i];
    var prev = trail.points[i - 1];
    var t = i / len;
    var alpha = t * t * 0.85;
    var size = t * 2.2;

    // Color shifts from teal to purple along trail
    var r = Math.floor(g.lerp(120, 0, t));
    var gr = Math.floor(g.lerp(80, 255, t));
    var b = Math.floor(g.lerp(255, 170, t));

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.strokeStyle = 'rgb(' + r + ',' + gr + ',' + b + ')';
    ctx.lineWidth = size;
    ctx.lineCap = 'round';
    ctx.shadowColor = 'rgba(' + r + ',' + gr + ',' + b + ',0.6)';
    ctx.shadowBlur = 4;
    ctx.beginPath();
    ctx.moveTo(prev.x, prev.y);
    ctx.lineTo(p.x, p.y);
    ctx.stroke();
    ctx.restore();
  }

  // Glow dot at trail head (oldest visible)
  var head = trail.points[0];
  ctx.save();
  ctx.globalAlpha = 0.18;
  ctx.fillStyle = '#00ffaa';
  ctx.shadowColor = '#00ffaa';
  ctx.shadowBlur = 8;
  ctx.fillRect(head.x - 1, head.y - 1, 2, 2);
  ctx.restore();
})

registerModule('Ambient Starfield', function(g) {
  g._stars = g._stars || (function() {
    var stars = [];
    for (var i = 0; i < 200; i++) {
      stars.push({
        x: Math.random() * 800,
        y: Math.random() * 600,
        z: Math.random(),
        size: Math.random() * 1.8 + 0.2,
        twinkle: Math.random() * Math.PI * 2,
        twinkleSpeed: Math.random() * 0.04 + 0.01,
        drift: (Math.random() - 0.5) * 0.08,
        color: (function() {
          var r = Math.random();
          if (r < 0.15) return { r: 180, g: 200, b: 255 };
          if (r < 0.30) return { r: 255, g: 220, b: 180 };
          if (r < 0.40) return { r: 255, g: 180, b: 180 };
          return { r: 220, g: 235, b: 255 };
        })()
      });
    }
    return stars;
  })();

  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var stars = g._stars;

  // Parallax offset based on player position
  var cx = g.px - W * 0.5;
  var cy = g.py - H * 0.5;

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Drift
    s.x += s.drift + s.z * (-g.vx * 0.012);
    s.y += s.z * (-g.vy * 0.012);
    s.twinkle += s.twinkleSpeed;

    // Wrap around canvas
    if (s.x < -2) s.x = W + 2;
    if (s.x > W + 2) s.x = -2;
    if (s.y < -2) s.y = H + 2;
    if (s.y > H + 2) s.y = -2;

    // Parallax screen position
    var sx = s.x - cx * s.z * 0.04;
    var sy = s.y - cy * s.z * 0.04;

    // Twinkle alpha
    var twinkleAmt = 0.5 + 0.5 * Math.sin(s.twinkle);
    var alpha = (0.3 + s.z * 0.55) * (0.7 + 0.3 * twinkleAmt);

    var c = s.color;
    var size = s.size * (0.85 + 0.15 * twinkleAmt);

    // Bright core
    ctx.globalAlpha = alpha;
    ctx.fillStyle = 'rgb(' + c.r + ',' + c.g + ',' + c.b + ')';
    ctx.beginPath();
    ctx.arc(sx, sy, size, 0, 6.2832);
    ctx.fill();

    // Glow halo for brighter stars
    if (s.z > 0.65 && size > 1.1) {
      ctx.globalAlpha = alpha * 0.18;
      ctx.beginPath();
      ctx.arc(sx, sy, size * 3.5, 0, 6.2832);
      ctx.fill();
    }
  }

  ctx.globalAlpha = 1;
})

registerModule('Floating Particle Spawner', function(g) {
  g._fps = g._fps || {
    particles: [],
    maxParticles: 120,
    spawnTimer: 0,
    spawnInterval: 8,
    colors: ['#00ffff','#ff00ff','#ffff00','#ff8800','#00ff88','#8800ff','#ff0044','#44ffff'],
    pulsePhase: 0
  };

  var s = g._fps;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var i, p, dx, dy, distSq, absorbRadius;

  s.pulsePhase += 0.04;
  s.spawnTimer++;

  absorbRadius = 12 + g.stage * 4;

  // Spawn new particles
  if (s.spawnTimer >= s.spawnInterval && s.particles.length < s.maxParticles) {
    s.spawnTimer = 0;

    var edge = Math.floor(g.rand(0, 4));
    var nx, ny;
    if (edge === 0) { nx = g.rand(0, W); ny = -6; }
    else if (edge === 1) { nx = g.rand(0, W); ny = H + 6; }
    else if (edge === 2) { nx = -6; ny = g.rand(0, H); }
    else { nx = W + 6; ny = g.rand(0, H); }

    var color = s.colors[Math.floor(g.rand(0, s.colors.length))];
    var size = g.rand(1.5, 4.5);
    var speed = g.rand(0.3, 1.4);
    var angle = Math.atan2(H / 2 - ny + g.rand(-H * 0.4, H * 0.4),
                           W / 2 - nx + g.rand(-W * 0.4, W * 0.4));

    s.particles.push({
      x: nx,
      y: ny,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      color: color,
      size: size,
      life: 1.0,
      decay: g.rand(0.0008, 0.002),
      wobbleAmp: g.rand(0.2, 0.8),
      wobbleFreq: g.rand(0.02, 0.06),
      wobbleOffset: g.rand(0, Math.PI * 2),
      age: 0,
      absorbed: false
    });
  }

  // Update and draw particles
  for (i = s.particles.length - 1; i >= 0; i--) {
    p = s.particles[i];

    p.age++;
    p.life -= p.decay;

    // Wobble perpendicular to velocity
    var wobble = Math.sin(p.age * p.wobbleFreq + p.wobbleOffset) * p.wobbleAmp;
    var perpX = -p.vy;
    var perpY = p.vx;
    var perpLen = Math.sqrt(perpX * perpX + perpY * perpY) || 1;
    p.x += p.vx + (perpX / perpLen) * wobble;
    p.y += p.vy + (perpY / perpLen) * wobble;

    // Check absorption by player
    dx = p.x - g.px;
    dy = p.y - g.py;
    distSq = dx * dx + dy * dy;

    if (distSq < absorbRadius * absorbRadius) {
      // Burst effect into shared particles
      for (var b = 0; b < 5; b++) {
        var ba = g.rand(0, Math.PI * 2);
        var bspd = g.rand(1, 3.5);
        g.particles.push({
          x: p.x, y: p.y,
          vx: Math.cos(ba) * bspd,
          vy: Math.sin(ba) * bspd,
          color: p.color,
          life: 1.0,
          decay: 0.04,
          size: p.size * 0.7
        });
      }
      g.score += 1;
      g.absorbed = (g.absorbed || 0) + 1;
      s.particles.splice(i, 1);
      continue;
    }

    // Remove dead or offscreen
    if (p.life <= 0 || p.x < -40 || p.x > W + 40 || p.y < -40 || p.y > H + 40) {
      s.particles.splice(i, 1);
      continue;
    }

    // Draw particle
    var alpha = Math.min(1, p.life * 3) * (0.6 + 0.4 * Math.sin(s.pulsePhase + p.wobbleOffset));
    var drawSize = p.size * (0.8 + 0.2 * Math.sin(p.age * 0.1 + p.wobbleOffset));

    ctx.save();
    ctx.globalAlpha = alpha;

    // Glow
    var grad = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, drawSize * 3);
    grad.addColorStop(0, p.color);
    grad.addColorStop(1, 'transparent');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(p.x, p.y, drawSize * 3, 0, Math.PI * 2);
    ctx.fill();

    // Core
    ctx.globalAlpha = alpha * 0.9;
    ctx.fillStyle = '#ffffff';
    ctx.beginPath();
    ctx.arc(p.x, p.y, drawSize * 0.5, 0, Math.PI * 2);
    ctx.fill();

    ctx.restore();
  }

  // Draw shared particle burst effects
  for (i = g.particles.length - 1; i >= 0; i--) {
    var ep = g.particles[i];
    if (!ep.size) continue;
    ep.life -= ep.decay;
    ep.x += ep.vx;
    ep.y += ep.vy;
    ep.vx *= 0.93;
    ep.vy *= 0.93;

    if (ep.life <= 0) {
      g.particles.splice(i, 1);
      continue;
    }

    ctx.save();
    ctx.globalAlpha = ep.life * 0.8;
    ctx.fillStyle = ep.color;
    ctx.beginPath();
    ctx.arc(ep.x, ep.y, ep.size * ep.life, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
})

registerModule('Pixel Glow', function(g) {
  g._glow = g._glow || { pulse: 0, trails: [] };

  var glow = g._glow;
  var ctx = g.ctx;

  // Advance pulse
  glow.pulse = (glow.pulse + 0.05) % (Math.PI * 2);

  // Record trail positions
  glow.trails.push({ x: g.px, y: g.py, age: 0 });
  if (glow.trails.length > 18) glow.trails.shift();

  // Draw motion trails
  for (var i = 0; i < glow.trails.length; i++) {
    var t = glow.trails[i];
    t.age++;
    var trailAlpha = (1 - t.age / 18) * 0.18;
    var trailRadius = (1 - t.age / 18) * 6;
    if (trailAlpha <= 0) continue;

    var tg = ctx.createRadialGradient(t.x, t.y, 0, t.x, t.y, trailRadius);
    tg.addColorStop(0, 'rgba(0,255,170,' + (trailAlpha * 2).toFixed(3) + ')');
    tg.addColorStop(1, 'rgba(0,255,170,0)');
    ctx.beginPath();
    ctx.arc(t.x, t.y, trailRadius, 0, Math.PI * 2);
    ctx.fillStyle = tg;
    ctx.fill();
  }

  // Outer soft ambient glow (large, very faint)
  var outerR = 48 + Math.sin(glow.pulse * 0.7) * 6;
  var og = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, outerR);
  og.addColorStop(0, 'rgba(0,255,170,0.07)');
  og.addColorStop(0.5, 'rgba(0,200,120,0.04)');
  og.addColorStop(1, 'rgba(0,255,170,0)');
  ctx.beginPath();
  ctx.arc(g.px, g.py, outerR, 0, Math.PI * 2);
  ctx.fillStyle = og;
  ctx.fill();

  // Mid glow ring
  var midR = 18 + Math.sin(glow.pulse * 1.3) * 3;
  var mg = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, midR);
  mg.addColorStop(0, 'rgba(0,255,170,0.22)');
  mg.addColorStop(0.6, 'rgba(0,255,170,0.08)');
  mg.addColorStop(1, 'rgba(0,255,170,0)');
  ctx.beginPath();
  ctx.arc(g.px, g.py, midR, 0, Math.PI * 2);
  ctx.fillStyle = mg;
  ctx.fill();

  // Inner bright core glow
  var coreR = 6 + Math.sin(glow.pulse * 2.1) * 1.2;
  var cg = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, coreR);
  cg.addColorStop(0, 'rgba(180,255,230,0.95)');
  cg.addColorStop(0.3, 'rgba(0,255,170,0.7)');
  cg.addColorStop(1, 'rgba(0,255,170,0)');
  ctx.beginPath();
  ctx.arc(g.px, g.py, coreR, 0, Math.PI * 2);
  ctx.fillStyle = cg;
  ctx.fill();

  // The player pixel itself — crisp center dot
  ctx.fillStyle = '#00ffaa';
  ctx.fillRect(g.px - 1, g.py - 1, 2, 2);

  // Sparkle micro-particles around core
  if (g.tick % 6 === 0) {
    var angle = g.rand(0, Math.PI * 2);
    var dist = g.rand(2, 10);
    g.particles.push({
      x: g.px + Math.cos(angle) * dist,
      y: g.py + Math.sin(angle) * dist,
      vx: Math.cos(angle) * g.rand(0.2, 0.8),
      vy: Math.sin(angle) * g.rand(0.2, 0.8),
      life: 1,
      decay: g.rand(0.04, 0.09),
      size: g.rand(0.5, 1.5),
      color: '0,255,170'
    });
  }

  // Render shared particles
  for (var p = g.particles.length - 1; p >= 0; p--) {
    var part = g.particles[p];
    part.x += part.vx;
    part.y += part.vy;
    part.life -= part.decay;
    if (part.life <= 0) {
      g.particles.splice(p, 1);
      continue;
    }
    ctx.globalAlpha = part.life * 0.8;
    ctx.fillStyle = 'rgb(' + part.color + ')';
    ctx.fillRect(part.x - part.size / 2, part.y - part.size / 2, part.size, part.size);
  }
  ctx.globalAlpha = 1;
})

registerModule('Enemy AI Spawner', function(g) {
  g._enemies = g._enemies || { list: [], spawnTimer: 0, spawnInterval: 180, maxEnemies: 12 };

  var e = g._enemies;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Spawn logic
  e.spawnTimer++;
  var difficulty = 1 + (g.stage || 0) * 0.4;
  var interval = Math.max(60, e.spawnInterval - (g.stage || 0) * 20);

  if (e.spawnTimer >= interval && e.list.length < e.maxEnemies + (g.stage || 0) * 2) {
    e.spawnTimer = 0;

    // Spawn from edges
    var side = Math.floor(g.rand(0, 4));
    var ex, ey;
    if (side === 0) { ex = g.rand(0, W); ey = -10; }
    else if (side === 1) { ex = W + 10; ey = g.rand(0, H); }
    else if (side === 2) { ex = g.rand(0, W); ey = H + 10; }
    else { ex = -10; ey = g.rand(0, H); }

    e.list.push({
      x: ex,
      y: ey,
      vx: 0,
      vy: 0,
      size: g.rand(3, 6 + (g.stage || 0)),
      speed: g.rand(0.8, 1.6) * difficulty,
      pulse: g.rand(0, Math.PI * 2),
      trail: [],
      alive: true
    });
  }

  // Update and draw enemies
  for (var i = e.list.length - 1; i >= 0; i--) {
    var en = e.list[i];

    // Chase player
    var dx = g.px - en.x;
    var dy = g.py - en.y;
    var d = Math.sqrt(dx * dx + dy * dy) || 1;
    var ax = (dx / d) * en.speed;
    var ay = (dy / d) * en.speed;

    // Slight wobble
    en.pulse += 0.08;
    ax += Math.sin(en.pulse * 1.3) * 0.3;
    ay += Math.cos(en.pulse * 0.9) * 0.3;

    en.vx = g.lerp(en.vx, ax, 0.12);
    en.vy = g.lerp(en.vy, ay, 0.12);
    en.x += en.vx;
    en.y += en.vy;

    // Trail
    en.trail.push({ x: en.x, y: en.y });
    if (en.trail.length > 8) en.trail.shift();

    // Draw trail
    for (var t = 0; t < en.trail.length; t++) {
      var alpha = (t / en.trail.length) * 0.35;
      var tr = en.trail[t];
      ctx.beginPath();
      ctx.arc(tr.x, tr.y, en.size * (t / en.trail.length) * 0.8, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(220,30,30,' + alpha + ')';
      ctx.fill();
    }

    // Pulse size
    var pSize = en.size + Math.sin(en.pulse * 2) * 1.2;

    // Glow
    var grad = ctx.createRadialGradient(en.x, en.y, 0, en.x, en.y, pSize * 3);
    grad.addColorStop(0, 'rgba(255,80,40,0.7)');
    grad.addColorStop(0.5, 'rgba(200,20,20,0.3)');
    grad.addColorStop(1, 'rgba(180,0,0,0)');
    ctx.beginPath();
    ctx.arc(en.x, en.y, pSize * 3, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();

    // Core
    ctx.beginPath();
    ctx.arc(en.x, en.y, pSize, 0, Math.PI * 2);
    ctx.fillStyle = 'rgb(255,60,40)';
    ctx.fill();

    // Bright center
    ctx.beginPath();
    ctx.arc(en.x, en.y, pSize * 0.4, 0, Math.PI * 2);
    ctx.fillStyle = 'rgb(255,220,200)';
    ctx.fill();

    // Collision with player
    var playerSize = 3 + (g.stage || 0);
    if (g.dist({ x: en.x, y: en.y }, { x: g.px, y: g.py }) < pSize + playerSize) {
      // Death burst particles
      for (var p = 0; p < 18; p++) {
        var angle = (p / 18) * Math.PI * 2;
        var spd = g.rand(2, 5);
        g.particles.push({
          x: g.px, y: g.py,
          vx: Math.cos(angle) * spd,
          vy: Math.sin(angle) * spd,
          life: 1, decay: g.rand(0.03, 0.07),
          size: g.rand(2, 5),
          color: p % 2 === 0 ? 'rgba(0,255,170,' : 'rgba(255,60,40,'
        });
      }

      // Reset player to center on death
      g.px = g.canvas.width / 2;
      g.py = g.canvas.height / 2;
      g.vx = 0;
      g.vy = 0;
      g.score = Math.max(0, (g.score || 0) - 50);

      // Clear enemies on respawn
      e.list = [];
      e.spawnTimer = 0;
      break;
    }

    // Remove if too far off screen
    if (en.x < -100 || en.x > W + 100 || en.y < -100 || en.y > H + 100) {
      e.list.splice(i, 1);
    }
  }

  // HUD: enemy count
  ctx.font = '11px monospace';
  ctx.fillStyle = 'rgba(255,80,60,0.7)';
  ctx.fillText('HOSTILES: ' + e.list.length, 10, 40);
})

registerModule('Score HUD', function(g) {
  g._hud = g._hud || {
    displayScore: 0,
    displayAbsorbed: 0,
    pulse: 0,
    lastScore: 0,
    flashTimer: 0
  };

  var h = g._hud;
  var ctx = g.ctx;

  // Smooth score interpolation
  h.displayScore = g.lerp(h.displayScore, g.score, 0.15);
  h.displayAbsorbed = g.lerp(h.displayAbsorbed, g.absorbed, 0.2);

  // Flash on score change
  if (g.score !== h.lastScore) {
    h.flashTimer = 18;
    h.lastScore = g.score;
  }
  if (h.flashTimer > 0) h.flashTimer--;

  // Pulse animation
  h.pulse = Math.sin(g.tick * 0.04) * 0.5 + 0.5;

  var flash = h.flashTimer / 18;
  var glowAlpha = 0.4 + h.pulse * 0.3 + flash * 0.6;
  var scoreColor = flash > 0
    ? 'rgba(' + Math.round(g.lerp(0, 255, flash)) + ', 255, ' + Math.round(g.lerp(170, 100, flash)) + ', 1)'
    : '#00ffaa';

  // HUD panel background
  ctx.save();
  ctx.globalAlpha = 0.55;
  ctx.fillStyle = '#020810';
  ctx.strokeStyle = 'rgba(0,255,170,0.18)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.roundRect(12, 12, 210, 78, 10);
  ctx.fill();
  ctx.stroke();
  ctx.globalAlpha = 1;

  // Glow effect behind score text
  ctx.shadowColor = '#00ffaa';
  ctx.shadowBlur = 14 + flash * 18;

  // SCORE label
  ctx.font = '700 11px monospace';
  ctx.letterSpacing = '3px';
  ctx.fillStyle = 'rgba(0,255,170,0.45)';
  ctx.fillText('SCORE', 28, 36);

  // Score value
  ctx.font = '700 28px monospace';
  ctx.fillStyle = scoreColor;
  ctx.fillText(Math.round(h.displayScore), 28, 62);

  // Stage indicator dots
  var stageMax = 5;
  for (var i = 0; i <= stageMax; i++) {
    var dotX = 152 + i * 11;
    var dotY = 56;
    var active = i <= g.stage;
    ctx.beginPath();
    ctx.arc(dotX, dotY, active ? 4 : 2.5, 0, Math.PI * 2);
    if (active) {
      ctx.fillStyle = 'rgba(0,255,170,' + (0.6 + glowAlpha * 0.4) + ')';
      ctx.shadowBlur = 8;
    } else {
      ctx.fillStyle = 'rgba(0,255,170,0.18)';
      ctx.shadowBlur = 0;
    }
    ctx.fill();
  }

  // STAGE label
  ctx.shadowBlur = 0;
  ctx.font = '700 9px monospace';
  ctx.fillStyle = 'rgba(0,255,170,0.35)';
  ctx.fillText('STAGE', 152, 44);

  // Divider line
  ctx.strokeStyle = 'rgba(0,255,170,0.12)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(26, 68);
  ctx.lineTo(200, 68);
  ctx.stroke();

  // ABSORBED label + count
  ctx.font = '700 10px monospace';
  ctx.fillStyle = 'rgba(0,255,170,0.38)';
  ctx.fillText('ABSORBED', 28, 82);

  ctx.font = '700 10px monospace';
  ctx.fillStyle = 'rgba(0,255,170,0.75)';
  ctx.fillText(Math.round(h.displayAbsorbed), 120, 82);

  // Animated corner accent top-left
  var accentLen = 10 + h.pulse * 4;
  ctx.strokeStyle = 'rgba(0,255,170,' + (0.5 + h.pulse * 0.5) + ')';
  ctx.lineWidth = 1.5;
  ctx.shadowColor = '#00ffaa';
  ctx.shadowBlur = 6;
  ctx.beginPath();
  ctx.moveTo(12, 12 + accentLen);
  ctx.lineTo(12, 12);
  ctx.lineTo(12 + accentLen, 12);
  ctx.stroke();

  // Animated corner accent bottom-right
  ctx.beginPath();
  ctx.moveTo(222, 90 - accentLen);
  ctx.lineTo(222, 90);
  ctx.lineTo(222 - accentLen, 90);
  ctx.stroke();

  ctx.shadowBlur = 0;
  ctx.restore();
})

registerModule('Absorption Field', function(g) {
  g._absField = g._absField || {
    active: false,
    radius: 0,
    maxRadius: 180,
    pulsePhase: 0,
    rings: [
      { phase: 0, speed: 0.04 },
      { phase: 2.1, speed: 0.06 },
      { phase: 4.2, speed: 0.05 }
    ],
    sparks: [],
