registerModule('Background Grid', function(g) {
  g._grid = g._grid || {
    offsetX: 0,
    offsetY: 0,
    lastPx: g.px,
    lastPy: g.py,
    pulse: 0
  };

  var grid = g._grid;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Track world scroll offset based on player movement
  var dx = g.px - grid.lastPx;
  var dy = g.py - grid.lastPy;
  grid.offsetX = (grid.offsetX - dx * 0.4) % 48;
  grid.offsetY = (grid.offsetY - dy * 0.4) % 48;
  grid.lastPx = g.px;
  grid.lastPy = g.py;

  // Pulse intensity based on player speed
  var speed = Math.sqrt(g.vx * g.vx + g.vy * g.vy);
  var targetPulse = speed / (g.speed * 2);
  grid.pulse = g.lerp(grid.pulse, targetPulse, 0.08);

  var cellSize = 48;
  var baseAlpha = 0.07 + grid.pulse * 0.13;
  var accentAlpha = 0.18 + grid.pulse * 0.22;

  // Draw minor grid lines
  ctx.save();
  ctx.strokeStyle = 'rgba(0, 255, 170, ' + baseAlpha + ')';
  ctx.lineWidth = 0.5;
  ctx.beginPath();

  var startX = (grid.offsetX % cellSize + cellSize) % cellSize;
  var startY = (grid.offsetY % cellSize + cellSize) % cellSize;

  for (var x = startX - cellSize; x < W + cellSize; x += cellSize) {
    ctx.moveTo(x, 0);
    ctx.lineTo(x, H);
  }
  for (var y = startY - cellSize; y < H + cellSize; y += cellSize) {
    ctx.moveTo(0, y);
    ctx.lineTo(W, y);
  }
  ctx.stroke();

  // Draw major grid lines every 4 cells
  var majorCell = cellSize * 4;
  var majorOffX = (grid.offsetX * 1 % majorCell + majorCell) % majorCell;
  var majorOffY = (grid.offsetY * 1 % majorCell + majorCell) % majorCell;

  ctx.strokeStyle = 'rgba(0, 200, 255, ' + accentAlpha + ')';
  ctx.lineWidth = 1;
  ctx.beginPath();

  var mStartX = (majorOffX % majorCell + majorCell) % majorCell;
  var mStartY = (majorOffY % majorCell + majorCell) % majorCell;

  for (var mx = mStartX - majorCell; mx < W + majorCell; mx += majorCell) {
    ctx.moveTo(mx, 0);
    ctx.lineTo(mx, H);
  }
  for (var my = mStartY - majorCell; my < H + majorCell; my += majorCell) {
    ctx.moveTo(0, my);
    ctx.lineTo(W, my);
