registerModule('Screen Shake VFX', function(g) {
  g._shake = g._shake || {
    intensity: 0,
    duration: 0,
    offsetX: 0,
    offsetY: 0,
    trauma: 0,
    lastScore: 0,
    lastAbsorbed: 0
  };

