    s.trauma = Math.min(1.0, s.trauma + amount);
  }

  // Expose shake trigger globally so other modules can call g.shake()
  g.shake = g.shake || addTrauma;

  // Detect score change / absorption as proxy for collision events
  if (s.lastScore !== undefined && g.score !== s.lastScore) {
    var delta = g.score - s.lastScore;
    if (delta < 0) {
      // Score dropped — took a hit
      addTrauma(0.6);
    }
  }

  if (g.absorbed !== s.lastAbsorbed) {
    var absorbDelta = g.absorbed - s.lastAbsorbed;
    if (absorbDelta > 0) {
      // Absorbed something — small positive shake
      addTrauma(0.25 + absorbDelta * 0.05);
    }
  }

  s.lastScore = g.score;
  s.lastAbsorbed = g.absorbed;

  // Decay trauma over time
  var decayRate = 0.035;
  s.trauma = Math.max(0, s.trauma - decayRate);

  // Compute shake from trauma squared (feel curve)
  var intensity = s.trauma * s.trauma;
  var maxOffset = 18;
  var maxRotation = 0.04;

  // Use smooth noise via sin harmonics for natural shake
  var t = g.tick;
  s.offsetX = intensity * maxOffset * (
    Math.sin(t * 0.97 * 1.1) * 0.6 +
    Math.sin(t * 2.33 * 1.1) * 0.3 +
    Math.sin(t * 5.17 * 1.1) * 0.1
  );
  s.offsetY = intensity * maxOffset * (
    Math.sin(t * 1.13 * 1.1 + 1.5) * 0.6 +
    Math.sin(t * 2.71 * 1.1 + 0.8) * 0.3 +
    Math.sin(t * 4.83 * 1.1 + 2.1) * 0.1
  );
  var rotation = intensity * maxRotation * Math.sin(t * 1.57);

  // Apply camera transform at start of frame
  ctx.save();
  ctx.translate(
    g.canvas.width * 0.5 + s.offsetX,
    g.canvas.height * 0.5 + s.offsetY
  );
  ctx.rotate(rotation);
  ctx.translate(-g.canvas.width * 0.5, -g.canvas.height * 0.5);

