    ctx.save();
    ctx.globalCompositeOperation = 'screen';
    ctx.globalAlpha = intensity * 0.18;
    ctx.fillStyle = 'rgba(255,0,0,1)';
    ctx.fillRect(aberration, 0, w, h);
    ctx.restore();

    // Blue channel ghost
    ctx.save();
    ctx.globalCompositeOperation = 'screen';
    ctx.globalAlpha = intensity * 0.18;
    ctx.fillStyle = 'rgba(0,80,255,1)';
    ctx.fillRect(-aberration, 0, w, h);
    ctx.restore();
  }

  // Vignette pulse on heavy trauma
  if (s.trauma > 0.3) {
    var vigAlpha = (s.trauma - 0.3) * 0.7;
    var grad = ctx.createRadialGradient(
      g.canvas.width * 0.5, g.canvas.height * 0.5, g.canvas.height * 0.2,
      g.canvas.width * 0.5, g.canvas.height * 0.5, g.canvas.height * 0.85
    );
    grad.addColorStop(0, 'rgba(180,0,0,0)');
    grad.addColorStop(1, 'rgba(180,0,0,' + vigAlpha.toFixed(3) + ')');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, g.canvas.width, g.canvas.height);
  }

  ctx.restore();

  // HUD: shake debug indicator (subtle, top-right)
  if (s.trauma > 0.01) {
    var barW = 60;
    var barH = 5;
    var bx = g.canvas.width - barW - 10;
    var by = 10;
    ctx.fillStyle = 'rgba(0,0,0,0.5)';
    ctx.fillRect(bx, by, barW, barH);
    var r = Math.floor(255 * s.trauma);
    var gv = Math.floor(255 * (1 - s.trauma));
    ctx.fillStyle = 'rgb(' + r + ',' + gv + ',0)';
    ctx.fillRect(bx, by, barW * s.trauma, barH);
    ctx.fillStyle = 'rgba(255,255,255,0.4)';
    ctx.font = '9px monospace';
    ctx.fillText('SHAKE', bx, by + barH + 9);
  }
})

